import {
  rectangle, rounded_rectangle, circle, polygon, segment,
  union, dilate, render,
} from '../../src/index.js';

// Bare-bones airport silhouette — terminal + 1 plane silhouette + runway.
// Intentionally minimal so atom adoption (airport-apron) has room to shine.

// Terminal building (long low block)
const terminal = rectangle([0.7, 0.18], [0, -0.10]);
const terminalRoof = polygon([
  [-0.35, -0.01],
  [ 0.35, -0.01],
  [ 0.30,  0.05],
  [-0.30,  0.05],
]);

// Tiny plane silhouette on tarmac (just one — atom will multiply)
const plane = ellipse(0.10, 0.018, [-0.20, -0.22]);

// Ground / runway strip
const ground = rectangle([1.6, 0.10], [0, -0.36]);
const runwayStrip = rectangle([1.4, 0.015], [0, -0.30]);

const sky = rectangle([1.6, 0.80], [0, 0.20]);

const layers = [
  { sdf: sky,               color: [150, 180, 210] },
  { sdf: ground,            color: [80,  85,  72]  },
  { sdf: runwayStrip,       color: [60,  65,  56]  },
  { sdf: dilate(terminal, 0.012), color: [20, 25, 35] },
  { sdf: terminal,          color: [220, 215, 200] },
  { sdf: terminalRoof,      color: [110, 90, 70] },
  { sdf: dilate(plane, 0.008), color: [20, 25, 35] },
  { sdf: plane,             color: [240, 240, 245] },
];
const canvas = document.getElementById('c');
const ctx = canvas.getContext('2d');
render.silhouette(ctx, layers, {
  view: 1.4,
  background: { top: [130, 165, 195], bottom: [195, 215, 230] },
});
